#include <iostream>
#include <limits> // For std::numeric_limits (optional, for max value)

int main() {
    short int num = 32767; // Maximum value for short int (from table)
    std::cout << "Initial short int (max value): " << num << std::endl;

    num = num + 1; // Attempt to exceed the maximum by adding 1
    std::cout << "short int after adding 1 (overflow): " << num << std::endl;

    // Explanation:
    // When a signed integer type like `short int` exceeds its maximum positive value,
    // it typically 'wraps around' to its minimum negative value. This phenomenon is
    // known as integer overflow. For a 2-byte `short int`, 32767 + 1 results in -32768.
    // This behavior is technically undefined behavior for signed integers in C++,
    // but most common systems implement two's complement arithmetic, leading to this wrap-around.
    // For unsigned integers, overflow is well-defined and wraps around modulo (MAX_VALUE + 1).

    return 0;
}
```

