    // It provides the necessary range to store 10 billion and explicitly indicates that the value will be non-negative.

    unsigned long long int total_sand_grains = 10000000000ULL; // ULL suffix for unsigned long long literal

    std::cout << "Total sand grains: " << total_sand_grains << std::endl;

