    // The 'LL' suffix ensures 9876543210987654321 is treated as a long long literal
    long long largeNumber = 9876543210987654321LL; // This value might exceed typical 64-bit signed long long max, use a smaller one for guaranteed compilation, e.g., 123456789012345LL
