```cpp
// Step 1: Declare and initialize variables
float price = 19.99f;
int quantity = 3;
int totalItemsCost;

// Step 2: Calculate the total cost (intermediate result will be float)
float calculatedCost = price * quantity; // calculatedCost will be 59.97

// Step 3: Assign the calculated cost to the integer variable
// The fractional part of calculatedCost will be truncated.
